(() => {
    type ICircularArray = {name: string; children?: ICircularArray[]};
    return {
      build: () => {
        const check = typia.createIs<ICircularArray>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<ICircularArray>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Recursive((This) => Type.Object({name: Type.String(), children: Type.Optional(Type.Array(This))}))
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({name: z.string(), children: z.array(z.lazy(() => schema)).optional()});
    return schema;
  }))
